/*!
 * IRLid local QR encoder (Version 6, EC=M, byte mode) — Deploy 36e
 * Exposes: window.QRCode.toCanvas(...)
 * Purpose: scannable QR without CDN dependency.
 * Deploy 41
 */
(function(global){
  "use strict";

  // ---- GF(256) tables (Reed–Solomon) ----
  const GF_EXP = new Uint8Array(512);
  const GF_LOG = new Uint8Array(256);
  (function initGF(){
    let x = 1;
    for (let i=0;i<255;i++){
      GF_EXP[i] = x;
      GF_LOG[x] = i;
      x <<= 1;
      if (x & 0x100) x ^= 0x11d;
    }
    for (let i=255;i<512;i++) GF_EXP[i] = GF_EXP[i-255];
  })();
  function gfMul(a,b){
    if (a===0 || b===0) return 0;
    return GF_EXP[GF_LOG[a] + GF_LOG[b]];
  }

  function rsGeneratorPoly(ecLen){
    let poly = [1];
    for (let i=0;i<ecLen;i++){
      const next = new Array(poly.length+1).fill(0);
      for (let j=0;j<poly.length;j++){
        next[j] ^= gfMul(poly[j], GF_EXP[i]);
        next[j+1] ^= poly[j];
      }
      poly = next;
    }
    return poly;
  }

  function rsComputeECC(data, ecLen){
    const gen = rsGeneratorPoly(ecLen);
    const ecc = new Array(ecLen).fill(0);
    for (let i=0;i<data.length;i++){
      const factor = data[i] ^ ecc[0];
      ecc.shift();
      ecc.push(0);
      for (let j=0;j<ecLen;j++){
        ecc[j] ^= gfMul(gen[j], factor);
      }
    }
    return ecc;
  }

  // ---- QR v6, EC=M parameters ----
  // Version 6: size=41 modules
  // Total codewords: 172
  // EC M: data=108, ecc=64
  // Block structure: 2 blocks, each 54 data codewords, 32 ecc codewords
  const V = 6;
  const SIZE = 41;
  const DATA_CW = 108;
  const ECC_CW = 64;
  const BLOCKS = 2;
  const DATA_PER_BLOCK = 54;
  const ECC_PER_BLOCK = 32;

  // Alignment pattern centers for version 6: [6, 34]
  const ALIGN = [6, 34];

  function utf8Bytes(str){
    const out = [];
    for (let i=0;i<str.length;i++){
      let c = str.charCodeAt(i);
      if (c < 0x80) out.push(c);
      else if (c < 0x800){
        out.push(0xC0 | (c >> 6));
        out.push(0x80 | (c & 0x3F));
      } else if (c >= 0xD800 && c <= 0xDBFF){
        i++;
        const c2 = str.charCodeAt(i);
        const u = 0x10000 + (((c & 0x3FF) << 10) | (c2 & 0x3FF));
        out.push(0xF0 | (u >> 18));
        out.push(0x80 | ((u >> 12) & 0x3F));
        out.push(0x80 | ((u >> 6) & 0x3F));
        out.push(0x80 | (u & 0x3F));
      } else {
        out.push(0xE0 | (c >> 12));
        out.push(0x80 | ((c >> 6) & 0x3F));
        out.push(0x80 | (c & 0x3F));
      }
    }
    return out;
  }

  function pushBits(arr, val, n){
    for (let i=n-1;i>=0;i--) arr.push((val>>i)&1);
  }

  function bitsToBytes(bits){
    const out = [];
    for (let i=0;i<bits.length;i+=8){
      let b = 0;
      for (let j=0;j<8;j++) b = (b<<1) | (bits[i+j] ? 1 : 0);
      out.push(b);
    }
    return out;
  }

  function makeCodewords(text){
    const data = utf8Bytes(text);

    // Build bitstream: mode(0100) + len(8 bits for v6) + data bytes + terminator + pad
    const bits = [];
    pushBits(bits, 0x4, 4);           // byte mode
    pushBits(bits, data.length, 8);   // length (v6 uses 8-bit length for byte mode)
    for (let i=0;i<data.length;i++) pushBits(bits, data[i], 8);

    // terminator up to 4 bits
    const maxBits = DATA_CW * 8;
    const remain = maxBits - bits.length;
    pushBits(bits, 0, Math.min(4, Math.max(0, remain)));

    // pad to byte boundary
    while (bits.length % 8 !== 0) bits.push(0);

    const bytes = bitsToBytes(bits);
    // pad codewords 0xEC, 0x11
    while (bytes.length < DATA_CW){
      bytes.push((bytes.length % 2 === 0) ? 0xEC : 0x11);
    }

    // split into 2 data blocks of 54
    const blocks = [];
    for (let b=0;b<BLOCKS;b++){
      const chunk = bytes.slice(b*DATA_PER_BLOCK, (b+1)*DATA_PER_BLOCK);
      const ecc = rsComputeECC(chunk, ECC_PER_BLOCK);
      blocks.push({ data: chunk, ecc });
    }

    // interleave data then ecc
    const out = [];
    for (let i=0;i<DATA_PER_BLOCK;i++){
      for (let b=0;b<BLOCKS;b++) out.push(blocks[b].data[i]);
    }
    for (let i=0;i<ECC_PER_BLOCK;i++){
      for (let b=0;b<BLOCKS;b++) out.push(blocks[b].ecc[i]);
    }

    // out length should be 172 codewords
    return out;
  }

  function makeMatrix(){
    const m = new Array(SIZE);
    for (let y=0;y<SIZE;y++){
      m[y] = new Array(SIZE).fill(null);
    }
    return m;
  }

  function setFinder(m, x, y){
    for (let dy=-1;dy<=7;dy++){
      for (let dx=-1;dx<=7;dx++){
        const xx = x+dx, yy=y+dy;
        if (xx<0||yy<0||xx>=SIZE||yy>=SIZE) continue;
        const on =
          (dx>=0&&dx<=6&&dy>=0&&dy<=6) &&
          (dx===0||dx===6||dy===0||dy===6 || (dx>=2&&dx<=4&&dy>=2&&dy<=4));
        m[yy][xx] = on ? 1 : 0;
      }
    }
  }

  function setAlignment(m, cx, cy){
    // 5x5 pattern centered at (cx,cy)
    for (let dy=-2;dy<=2;dy++){
      for (let dx=-2;dx<=2;dx++){
        const xx = cx+dx, yy = cy+dy;
        if (xx<0||yy<0||xx>=SIZE||yy>=SIZE) continue;
        const adx = Math.abs(dx), ady = Math.abs(dy);
        const on = (adx===2 || ady===2 || (adx===0 && ady===0));
        m[yy][xx] = on ? 1 : 0;
      }
    }
  }

  function setTiming(m){
    for (let i=8;i<SIZE-8;i++){
      const v = (i % 2 === 0) ? 1 : 0;
      if (m[6][i] === null) m[6][i] = v;
      if (m[i][6] === null) m[i][6] = v;
    }
  }

  function reserveFormat(m){
    // top-left
    for (let i=0;i<9;i++){
      if (m[8][i] === null) m[8][i] = 0;
      if (m[i][8] === null) m[i][8] = 0;
    }
    // top-right
    for (let i=0;i<8;i++){
      if (m[i][SIZE-8] === null) m[i][SIZE-8] = 0;
      if (m[8][SIZE-1-i] === null) m[8][SIZE-1-i] = 0;
    }
    // bottom-left
    for (let i=0;i<8;i++){
      if (m[SIZE-8][i] === null) m[SIZE-8][i] = 0;
      if (m[SIZE-1-i][8] === null) m[SIZE-1-i][8] = 0;
    }
    // dark module for v6 at (4*V+9,8) => (33,8) in row/col? Spec: (row=4V+9, col=8)
    m[4*V + 9][8] = 1;
  }

  function isInFinderRegion(x,y){
    // Finder + separator areas: 9x9 at corners
    const inTL = x<=8 && y<=8;
    const inTR = x>=SIZE-9 && y<=8;
    const inBL = x<=8 && y>=SIZE-9;
    return inTL || inTR || inBL;
  }

  function setAlignments(m){
    for (let i=0;i<ALIGN.length;i++){
      for (let j=0;j<ALIGN.length;j++){
        const cx = ALIGN[i], cy = ALIGN[j];
        // skip those overlapping finder regions
        if (isInFinderRegion(cx, cy)) continue;
        setAlignment(m, cx, cy);
      }
    }
  }

  function placeData(m, codewords){
    const totalBits = codewords.length * 8;
    let bitIdx = 0;

    function getBit(){
      if (bitIdx >= totalBits) return 0;
      const cw = codewords[bitIdx >> 3];
      const b = (cw >> (7 - (bitIdx & 7))) & 1;
      bitIdx++;
      return b;
    }

    let x = SIZE - 1;
    let y = SIZE - 1;
    let dir = -1;

    while (x > 0){
      if (x === 6) x--; // timing column

      for (let i=0;i<SIZE;i++){
        const yy = y + dir*i;
        for (let dx=0;dx<2;dx++){
          const xx = x - dx;
          if (m[yy][xx] !== null) continue;

          let v = getBit();

          // Mask pattern 0: (r+c)%2==0
          if (((yy + xx) & 1) === 0) v ^= 1;

          m[yy][xx] = v;
        }
      }

      y = y + dir*(SIZE-1);
      dir = -dir;
      x -= 2;
    }
  }

  // BCH for format info. EC=M (01), mask=0 -> data bits = 0b01000 = 0x08
  // Format = BCH(0x08) XOR 0x5412
  function bchFormat(ecMaskBits){
    let d = ecMaskBits << 10;
    const g = 0x537; // 10100110111
    function msb(n){ let c=0; while(n){ n>>=1; c++; } return c; }
    while (msb(d) - msb(g) >= 0){
      d ^= (g << (msb(d) - msb(g)));
    }
    return ((ecMaskBits << 10) | d) ^ 0x5412;
  }

  function setFormatBits(m){
    const format = bchFormat(0x08); // M + mask0
    function bit(i){ return (format >> i) & 1; }

    // Place 15 bits (MSB..LSB mapping)
    // Following common placement order:
    for (let i=0;i<=5;i++) m[i][8] = bit(14 - i);
    m[7][8] = bit(8);
    m[8][8] = bit(7);
    m[8][7] = bit(6);
    for (let i=0;i<=5;i++) m[8][5 - i] = bit(i);

    // top-right
    for (let i=0;i<8;i++) m[8][SIZE-1-i] = bit(14 - i);

    // bottom-left
    for (let i=0;i<7;i++) m[SIZE-1-i][8] = bit(6 - i);
  }

  function buildMatrix(text){
    const m = makeMatrix();
    setFinder(m, 0, 0);
    setFinder(m, SIZE-7, 0);
    setFinder(m, 0, SIZE-7);
    setTiming(m);
    setAlignments(m);
    reserveFormat(m);

    const codewords = makeCodewords(text);
    placeData(m, codewords);
    setFormatBits(m);

    // fill any remaining nulls with 0
    for (let y=0;y<SIZE;y++){
      for (let x=0;x<SIZE;x++){
        if (m[y][x] === null) m[y][x] = 0;
      }
    }
    return m;
  }

  function drawToCanvas(canvas, text, width, margin){
    const m = buildMatrix(text);
    const modules = SIZE;

    const px = Math.max(128, (width|0) || 256);
    const qMargin = Math.max(0, margin|0);

    // compute scale and final size
    const inner = px - 2*qMargin;
    const scale = Math.max(1, Math.floor(inner / modules));
    const size = modules * scale + 2*qMargin;

    canvas.width = size;
    canvas.height = size;

    const ctx = canvas.getContext("2d");
    ctx.clearRect(0,0,size,size);
    ctx.fillStyle = "#fff";
    ctx.fillRect(0,0,size,size);

    ctx.fillStyle = "#000";
    for (let y=0;y<modules;y++){
      for (let x=0;x<modules;x++){
        if (m[y][x]){
          ctx.fillRect(qMargin + x*scale, qMargin + y*scale, scale, scale);
        }
      }
    }
  }

  function getCanvasTarget(target){
    if (typeof target === "string") {
      const el = document.getElementById(target);
      if (!el) throw new Error("toCanvas target id not found: " + target);
      return el;
    }
    return target;
  }

  global.QRCode = global.QRCode || {};
  global.QRCode.toCanvas = function(target, text, opts, cb){
    if (typeof opts === "function"){ cb = opts; opts = null; }
    opts = opts || {};
    cb = cb || function(){};

    try{
      let host = getCanvasTarget(target);
      let canvas = host;

      if (canvas && canvas.nodeType === 1 && canvas.tagName && canvas.tagName.toLowerCase() !== "canvas"){
        host.innerHTML = "";
        canvas = document.createElement("canvas");
        host.appendChild(canvas);
      }
      if (!canvas || !canvas.getContext) throw new Error("toCanvas target is not a canvas (or host element)");

      const width = opts.width || opts.size || 256;
      const margin = (opts.margin != null) ? opts.margin : 4;
      drawToCanvas(canvas, String(text), width, margin);
      cb(null);
    }catch(e){
      cb(e);
    }
  };

})(typeof window !== "undefined" ? window : this);
